import{_ as o,o as t,c as a,a3 as r}from"./chunks/framework.CjquFG0V.js";const u=JSON.parse('{"title":"69. Public Holidays","description":"","frontmatter":{"title":"69. Public Holidays","eba":"Health Allied & Managers Admin 2021-2025","topics":["leave","public-holidays","preliminary"]},"headers":[],"relativePath":"ebas/has-managers-admin/common-terms/leave/69-public-holidays.md","filePath":"ebas/has-managers-admin/common-terms/leave/69-public-holidays.md"}'),n={name:"ebas/has-managers-admin/common-terms/leave/69-public-holidays.md"};function s(i,e,l,h,p,d){return t(),a("div",null,[...e[0]||(e[0]=[r('<h1 id="_69-public-holidays" tabindex="-1">69. Public Holidays <a class="header-anchor" href="#_69-public-holidays" aria-label="Permalink to &quot;69. Public Holidays&quot;">​</a></h1><p><strong>69.1</strong> Entitlement to be absent on a public holiday</p><p><strong>(a)</strong> An Employee is entitled to be absent from his or her employment on a day or part-day that is a public holiday in the place where the Employee is based for work purposes.</p><p><strong>(b)</strong> However, an Employer may request an Employee to work on a public holiday if the request is reasonable.</p><p><strong>(c)</strong> If an Employer requests an Employee to work on a public holiday, the Employee may refuse the request if:</p><p><strong>(i)</strong> the request is not reasonable; or</p><p><strong>(ii)</strong> the refusal is reasonable.</p><p><strong>(d)</strong> In determining whether a request, or a refusal of a request, to work on a public holiday is reasonable, the following must be taken into account:</p><p><strong>(i)</strong> the nature of the Employer’s workplace or enterprise (including its operational requirements), and the nature of the work performed by the Employee;</p><p><strong>(ii)</strong> the Employee’s personal circumstances, including family responsibilities;</p><p><strong>(iii)</strong> whether the Employee could reasonably expect that the Employer might request work on the public holiday;</p><p><strong>(iv)</strong> whether the Employee is entitled to receive overtime payments, penalty rates or other compensation for, or a level of remuneration that reflects an expectation of, work on the public holiday;</p><p><strong>(v)</strong> the type of employment of the Employee (for example, whether full-time, part-time, casual or shiftwork);</p><p><strong>(vi)</strong> the amount of notice in advance of the public holiday given by the Employer when making the request;</p><p><strong>(vii)</strong> in relation to the refusal of a request – the amount of notice in advance of the public holiday given by the Employee when refusing the request; and</p><p><strong>(viii)</strong> any other relevant matter.</p><p><strong>69.2</strong> Meaning of public holiday</p><p><strong>(a)</strong> Employees will be entitled to the following public holidays:</p><p><strong>(b)</strong> 1 January (New Year’s Day)</p><p><strong>(c)</strong> 26 January (Australia Day)</p><p><strong>(d)</strong> Labour Day</p><p><strong>(e)</strong> Good Friday</p><p><strong>(f)</strong> Easter Saturday</p><p><strong>(g)</strong> Easter Monday</p><p><strong>(h)</strong> 25 April (ANZAC Day)</p><p><strong>(i)</strong> Queen’s Birthday</p><p><strong>(j)</strong> Melbourne Cup Day</p><p><strong>(k)</strong> 25 December (Christmas Day)</p><p><strong>(l)</strong> 26 December (Boxing Day)</p><p><strong>69.3</strong> Days-In-Lieu</p><p><strong>(a)</strong> When Christmas Day falls on a Saturday or Sunday, a holiday in lieu thereof will be observed on 27 December.</p><p><strong>(b)</strong> When Boxing Day falls on a Saturday or Sunday, a holiday in lieu thereof will be observed on 28 December</p><p><strong>(c)</strong> When New Year’s Day falls on a Saturday or Sunday a holiday in lieu thereof will be observed on the next Monday</p><p><strong>(d)</strong> When Australia Day falls on a Saturday or Sunday a holiday in lieu thereof will be observed on the next Monday</p><p><strong>(e)</strong> When ANZAC Day falls on a Sunday, a holiday in lieu thereof will be observed on the following Monday.</p><p><strong>(f)</strong> When ANZAC Day falls on Easter Monday, a holiday in lieu thereof will be observed on the following Tuesday.</p><p><strong>69.4</strong> Additional Days</p><p><strong>(a)</strong> Where in the State or Locality, public holidays are declared or prescribed on days other than those set out in subclauses 69.2 and</p><p><strong>69.3</strong> above, those days will constitute additional holidays for the purposes of the Agreement.</p><p><strong>69.5</strong> Substitute Days</p><p><strong>(a)</strong> An Employer and their Employees may agree to substitute another day for any prescribed in this clause. For this purpose the consent of the majority of affected Employees will constitute agreement.</p><p><strong>(b)</strong> An agreement pursuant to subclause 69.5(a) will be recorded in writing and be available to every affected Employee.</p><p><strong>(c)</strong> The HWU will be informed of an agreement made in accordance with subclause 69.5(a) and will have seven days in which to refuse to</p><p>accept it. The HWU will not unreasonably refuse to accept an agreement made under subclause 69.5(a) .</p><p><strong>(d)</strong> If the HWU refuses to accept an agreement made under subclause 69.5(a), the parties will seek to resolve the matter in accordance with <a href="/eba/ebas/has-managers-admin/common-terms/consultation-disputes/17-dispute-resolution-procedure.html">clause 17</a> (Dispute Resolution Procedure) of this Agreement.</p><p><strong>69.6</strong> Substitution of religious public holidays</p><p><strong>(a)</strong> Subject to the ongoing operational needs of the Employer, an Employee may, with the prior agreement of the Employer, substitute a public holiday as defined in this clause with a nominated religious holiday that is not a defined public holiday.</p><p><strong>(b)</strong> Where a religious holiday is nominated to be a substitute and the Employee works on the defined public holiday they will be paid at ordinary time and will be allowed time off on the nominated religious day without loss of pay. Applications are to be made at least one month in advance of the date on which the nominated religious holiday occurs, and the public holiday being substituted.</p><p><strong>69.7</strong> Substitution of public holidays during NAIDOC week</p><p><strong>(a)</strong> Where an Employer receives a request to substitute a public holiday in accordance with clause 69.5 of this Agreement for a day during NAIDOC week, the Employer will consider all the circumstances including:</p><p><strong>(i)</strong> any reason identified by the Employee with respect to the request; and</p><p><strong>(ii)</strong> the operational requirements of the Employer.</p><p><strong>(b)</strong> An Employer will not unreasonably refuse a request to substitute a public holiday under this subclause.</p><p><strong>69.8</strong> Payment for work on public holiday</p><p><strong>(a)</strong> An Employee, other than a casual Employee, who performs work (including overtime work) on a public holiday will be entitled to be paid 200% (based on 1/38th of the weekly salary set out in Schedule 2B or <a href="/eba/ebas/has-managers-admin/schedules/3b-wage-rates-managers-and-administrative-workers.html">Schedule 3B</a>) for the time worked on a public holiday; or</p><p><strong>(b)</strong> 250% (based on 1/38th of the weekly salary set out in <a href="/eba/ebas/has-managers-admin/schedules/2b-wage-rates-health-allied-services.html">Schedule 2B</a> or <a href="/eba/ebas/has-managers-admin/schedules/3b-wage-rates-managers-and-administrative-workers.html">Schedule 3B</a> for the time worked on a public holiday on a Saturday or Sunday (which is inclusive of the rates in Section 2 <a href="/eba/ebas/allied-health/employment/27-transition-to-retirement.html">clause 27</a> and Section 3 <a href="/eba/ebas/has-managers-admin/common-terms/preliminary/10-best-practice-employment-commitment.html">clause 10</a> (Weekend work)).</p><p><strong>(c)</strong> A Casual Employee who performs work (including overtime work) on a public holiday will be entitled to be paid 175% (based on 1/38th of the weekly salary set out in <a href="/eba/ebas/has-managers-admin/schedules/2b-wage-rates-health-allied-services.html">Schedule 2B</a> or <a href="/eba/ebas/has-managers-admin/schedules/3b-wage-rates-managers-and-administrative-workers.html">Schedule 3B</a>) for the time worked on a public holiday.</p><p><strong>69.9</strong> Public holiday not worked entitlement</p><p>This clause does not apply to casual employees</p><p><strong>(a)</strong> An Employee who is not ordinarily required to work on the day on which a public holiday is observed will not be entitled to the Rostered Off Benefit provided in clause 69.10.</p><p><strong>(b)</strong> In determining whether an Employee is ordinarily required to work on the day on which a public holiday is observed, the Employer will review the Employee’s roster pattern over the preceding six-month period. If the rosters show that the Employee has worked 50% or more of the days on which a particular public holiday falls, the Employee will be entitled to receive the Rostered Off Benefit for that public holiday (see clause 69.10).</p><p>Example 1: A full-time or part-time employee who only works Monday to Friday will not receive a Rostered Off Benefit for a public holidays that occur on a Saturday or Sunday. Example 2: A full-time employee works a rotating roster and has worked more than 50% of Saturdays in the preceding 6-month period. The employee is rostered to work Monday to Friday in a week where a public holiday falls on the Saturday. The employee will receive the Rostered Off Benefit at clause 69.10 in addition to their contracted hours for that week (i.e. 38 hours of ordinary pay plus the equivalent of 1.5 days’ ordinary pay or TOIL or Annual Leave credit).</p><p><strong>69.10</strong> Rostered Off Benefit</p><p><strong>(a)</strong> Subject to subclauses 69.9(a) and 69.9(b), a full-time or part-time Employee will receive a sum equal to 150% (based on 1/38th of the weekly salary set out in <a href="/eba/ebas/has-managers-admin/schedules/2b-wage-rates-health-allied-services.html">Schedule 2B</a> or <a href="/eba/ebas/has-managers-admin/schedules/3b-wage-rates-managers-and-administrative-workers.html">Schedule 3B</a>) for public holidays that occur on the Employee’s Rostered Day Off, or, if the Employer and Employee so agree:</p><p><strong>(i)</strong> the Employee may take one day and one half off in lieu within four weeks of the public holiday; or</p><p><strong>(ii)</strong> have one and one half days added to their annual leave.</p><p><strong>69.11</strong> Payment for absence on public holiday</p><p><strong>(a)</strong> If an Employee is absent from their employment on a day or part-day that is a public holiday, the Employer must pay the Employee at the Employee’s base rate of pay for the Employee’s ordinary hours of work on the day or part-day.</p><p><strong>(a)</strong> For the purposes of subclause 69.11(a) absent from employment means that the employee was rostered to work on the day that the public holiday was observed but was given the day off by the Employer.</p><p>Example: A part-time employee works an 8-hour shift on every Monday, Wednesday and Friday. The employer confirms that the employee is not required to work their rostered Friday shift due to a public holiday on that day. The employee will receive the entitlement of one day’s pay in accordance with clause 69.11.</p><p><strong>69.12</strong> Public holidays and Accrued Days Off Where an Employee’s accrued day off falls on a public holiday, another day will be determined by the Employer to be taken in lieu thereof, within the same 4-week cycle (where practicable).</p><p><strong>(a)</strong> a particular public holiday falls, the Employee will be entitled to receive the ‘rostered off&#39; benefit for that public holiday (see subclause 69.10).</p><p>PART H – UNION AND OTHER RESOURCES</p><p>Plain language terms: public holiday pay, holiday pay, PH pay, penalty rates holidays.</p>',74)])])}const m=o(n,[["render",s]]);export{u as __pageData,m as default};
